mapper.select:
SELECT account_no, member_id, bank_code, balance, hold_amount, account_status
FROM ACCOUNT
WHERE account_no = #{accountNo}

mapper.update:
UPDATE ACCOUNT
SET balance = balance - #{amount}
WHERE account_no = #{accountNo}
  AND balance >= #{amount}

UPDATE ACCOUNT
SET balance = balance + #{amount}
WHERE account_no = #{accountNo}

UPDATE ACCOUNT
SET hold_amount = hold_amount + #{amount}
WHERE account_no = #{accountNo}

UPDATE ACCOUNT
SET hold_amount = hold_amount - #{amount}
WHERE account_no = #{accountNo}
  AND hold_amount >= #{amount}
